@tool
def stripe_refund_charge(charge_id: str, amount_cents: int, idempotency_key: str) -> Refund:
    if hit := key_store.get(idempotency_key):
        return hit  # replay — no second refund
    refund = stripe.Refund.create(charge=charge_id, amount=amount_cents,
                                  idempotency_key=idempotency_key)
    key_store.set(idempotency_key, refund, ttl_seconds=86400)
    return refund

@tool
def send_email(to: str, subject: str, body: str) -> dict:
    return mailer.send(to=to, subject=subject, body=body)  # no key, no dedup
